form:Form.form:Scripts:
		function ONLOAD()
{ 
 	var estado = Ctrl('c_estado').GetCValue();

	// Actualizar MONTO PENDIENTE cuando es de liquidacion manual
  //if (Ctrl('main').GetMode() != "LIST" && Ctrl('main').GetMode() != "LIST_EDIT" )  
 	//	Ctrl('n_imp_pendiente').SetTypedValue(str2number(Ctrl('pendiente').GetXValue()));

	if (Ctrl('main').GetMode() == "EDIT")
	{
	  if (estado == "S")
	  {
	  	CtrlEnabled('f_anticipo',    true);
	  	CtrlEnabled('n_importe',     true);
	  	CtrlEnabled('e_cant_cuotas', true);
	  	CtrlEnabled('e_periodo',     true);
	  	CtrlEnabled('l_liquida',     true);    
	  	CtrlEnabled('e_quincena',    true);
	  	CtrlEnabled('DELETE', 			 true);
	  	CtrlEnabled('RECHAZADO', 		 true);
	  	CtrlEnabled('OTORGADO', 		 true);
	    CtrlEnabled('DESC_ANTI',  	 true);
	    CtrlEnabled('OTORGADO', 		 true);
	    CtrlEnabled('LIQUIDADO', 		 false);
	    CtrlEnabled('DESCONTADO', 	 false);
	    CtrlEnabled('FINALIZADO', 	 false);
	    CtrlEnabled('CANCELADO', 		 false);

	  } else
		  {		  	
		  	CtrlEnabled('f_anticipo',    false);
		  	CtrlEnabled('n_importe',     false);
		  	CtrlEnabled('e_cant_cuotas', false);
		  	CtrlEnabled('e_periodo',     false);
		  	CtrlEnabled('l_liquida',     false); 
		  	CtrlEnabled('e_quincena',    false);
		  	CtrlEnabled('DELETE', 			 false);
		  	CtrlEnabled('RECHAZADO',	 	 false);
		  	CtrlEnabled('OTORGADO', 		 false);
		  }

	  if (estado == "F" || estado == "C" || estado == "R")
	  {
	  	CtrlEnabled('CANCELADO', 			 false);
	  	CtrlEnabled('RECHAZADO', 			 false);
	  	CtrlEnabled('FINALIZADO', 		 false);
	  	CtrlEnabled('DESC_ANTI', 			 false);
	    CtrlEnabled('OTORGADO', 		 	 false);
	    CtrlEnabled('LIQUIDADO', 		 	 false);
	    CtrlEnabled('DESCONTADO', 	 	 false);	  	
	  }


	  if ((estado == "O" || estado == "L" || estado == "D") && (Ctrl('l_liquida').GetXValue() == "1"))
	  {
	    CtrlEnabled('CANCELADO', 		true);
	    CtrlEnabled('DESC_ANTI', 		false);
	    CtrlEnabled('OTORGADO', 		false);
	    CtrlEnabled('LIQUIDADO', 		false);
	    CtrlEnabled('DESCONTADO', 	false);
	    CtrlEnabled('FINALIZADO', 	false);
	  }

		if (Ctrl('l_liquida').GetXValue() == "0" && (estado == "O" || estado == "L" || estado == "D"))
		{	                                   
			CtrlEnabled('DESC_ANTI', 		true);
			CtrlEnabled('CANCELADO', 		true);
	    CtrlEnabled('OTORGADO', 		true);
	    CtrlEnabled('LIQUIDADO', 		true);
	    CtrlEnabled('DESCONTADO', 	true);
			CtrlEnabled('FINALIZADO', 	true);
			if (estado == "O") 
			{
				CtrlEnabled('OTORGADO', 		false);				
				CtrlEnabled('DESCONTADO', 	false);				
				CtrlEnabled('FINALIZADO', 	false);
			}
			if (estado == "L") 
			{
				CtrlEnabled('LIQUIDADO', 		false);			
				CtrlEnabled('OTORGADO', 		false);	
				CtrlEnabled('FINALIZADO', 	false);				
			}		
			if (estado == "D") 
			{                                     
				CtrlEnabled('OTORGADO', 		false);				
				CtrlEnabled('LIQUIDADO', 		false);
				CtrlEnabled('DESCONTADO', 	false);				
			}
		}
	}				

}

function Pendiente()
{
 	if (Ctrl('main').GetMode() == "EDIT" || Ctrl('main').GetMode() == "NEW")
 	{
 		Ctrl('n_imp_pendiente').SetCValue(Ctrl('n_importe').GetCValue());
 	}
}

function RECHAZADO()
{
	Ctrl('f_rechazo').SetXValue(date2str(Now()));
	Ctrl('c_estado').SetCValue("R");
	//Ctrl('n_imp_pendiente').SetTypedValue(0);
	return true;
}

function CANCELADO()
{
	Ctrl('f_cancelacion').SetXValue(date2str(Now()));
	Ctrl('c_estado').SetCValue("C");
	//Ctrl('n_imp_pendiente').SetTypedValue(0);
	return true;
}

function OTORGADO()
{                                           
	var temp = 0;
	if (Ctrl('f_anticipo').GetXValue() == '') 
		temp = 1
	if (Ctrl('n_importe').GetXValue() == '') 
		temp = 1
	if (Ctrl('e_cant_cuotas').GetXValue() == '') 
		temp = 1
	if (Ctrl('e_periodo').GetXValue() == '') 
		temp = 1
	if (temp == 0) 
	{		
		return true;  
	}
	else
		{             
			alert("Debe Completar los datos necesarios: Fecha de Anticipo, Importe, Cantidad de Cuotas, Periodo");
			return false;
		}

}

function FINALIZADO()
{
	Ctrl('c_estado').SetCValue("F");	
	return true;
}

function LIQUIDADO()
{	
	Ctrl('c_estado').SetCValue("L");	
	return true;
}

function DESCONTADO()
{	
	Ctrl('c_estado').SetCValue("D");	
	return true;
}
